// heys_app_gate_state_v1.js — gate/desktop/consent state builder

(function () {
    const HEYS = window.HEYS = window.HEYS || {};
    HEYS.AppGateState = HEYS.AppGateState || {};

    HEYS.AppGateState.useGateState = function ({
        React,
        AppGateFlow,
        AppDesktopGate,
        DesktopGateScreen,
        U,
        cloudUser,
        clientId,
        clients,
        clientsSource,
        clientSearch,
        setClientSearch,
        setClientId,
        cloudSignIn,
        handleSignOut,
        getClientStats,
        formatLastActive,
        getAvatarColor,
        getClientInitials,
        renameClient,
        editClient,
        removeClient,
        addClientToCloud,
        newName,
        setNewName,
        newPhone,
        setNewPhone,
        newPin,
        setNewPin,
        curatorTab,
        setCuratorTab,
        needsConsent,
        checkingConsent,
        setNeedsConsent,
        setShowMorningCheckin,
        isInitializing,
    }) {
        const gate = AppGateFlow.buildGate ? AppGateFlow.buildGate({
            clientId,
            isInitializing,
            cloudUser,
            clients,
            clientsSource,
            clientSearch,
            setClientSearch,
            setClientId,
            cloudSignIn,
            handleSignOut,
            U,
            getClientStats,
            formatLastActive,
            getAvatarColor,
            getClientInitials,
            renameClient,
            editClient,
            removeClient,
            addClientToCloud,
            newName,
            setNewName,
            newPhone,
            setNewPhone,
            newPin,
            setNewPin,
            curatorTab,
            setCuratorTab,
        }) : null;

        // 🖥️ Desktop Gate — заглушка для клиентов на широких экранах
        // Определяем куратор ли это (есть user object после curator login)
        const desktopGateState = AppDesktopGate.useDesktopGateState
            ? AppDesktopGate.useDesktopGateState({ React })
            : { isDesktop: window.innerWidth > 768, isCurator: false };
        const { isDesktop, isCurator } = desktopGateState;

        // Читаем desktopAllowed из профиля
        const profile = U?.lsGet ? U.lsGet('heys_profile', {}) : {};
        const desktopAllowed = profile?.desktopAllowed === true;

        // Desktop Gate: если клиент на десктопе и десктоп НЕ разрешён
        const desktopGate = AppGateFlow.buildDesktopGate ? AppGateFlow.buildDesktopGate({
            gate,
            isDesktop,
            isCurator,
            desktopAllowed,
            DesktopGateScreen,
            setClientId,
        }) : null;

        // 📜 Consent Gate: если клиенту нужно подписать согласия
        // Показывается после логина, но ДО основного приложения
        const consentGate = AppGateFlow.buildConsentGate ? AppGateFlow.buildConsentGate({
            gate,
            desktopGate,
            cloudUser,
            clientId,
            needsConsent,
            checkingConsent,
            setNeedsConsent,
            setShowMorningCheckin,
        }) : null;

        return {
            gate,
            desktopGate,
            consentGate,
            isDesktop,
            isCurator,
            desktopAllowed,
        };
    };
})();


/* ===== heys_app_global_bindings_v1.js ===== */
// heys_app_global_bindings_v1.js — window bindings for saveClientKey + backupManager

(function () {
    const HEYS = window.HEYS = window.HEYS || {};
    HEYS.AppGlobalBindings = HEYS.AppGlobalBindings || {};

    HEYS.AppGlobalBindings.useGlobalBindings = function ({
        React,
        cloud,
        clientId,
        backupAllKeys,
        restoreFromBackup,
        restoreFromBackupFile,
        backupMeta,
    }) {
        const { useEffect } = React;

        useEffect(() => {
            window.HEYS = window.HEYS || {};
            window.HEYS.saveClientKey = function (...args) {
                if (cloud && typeof cloud.saveClientKey === 'function') {
                    if (args.length === 3) {
                        // Новый формат: (clientId, key, value)
                        const [cid, k, v] = args;
                        cloud.saveClientKey(cid, k, v);
                    } else if (args.length === 2) {
                        // Старый формат: (key, value) — используем clientId из замыкания
                        const [k, v] = args;
                        if (clientId) {
                            cloud.saveClientKey(clientId, k, v);
                        }
                    }
                }
            };
        }, [cloud, clientId]);

        useEffect(() => {
            window.HEYS = window.HEYS || {};
            window.HEYS.backupManager = window.HEYS.backupManager || {};
            window.HEYS.backupManager.backupAll = backupAllKeys;
            window.HEYS.backupManager.restore = restoreFromBackup;
            window.HEYS.backupManager.restoreFromFile = restoreFromBackupFile;
            window.HEYS.backupManager.getLastBackupMeta = () => backupMeta;
        }, [backupAllKeys, restoreFromBackup, restoreFromBackupFile, backupMeta]);
    };
})();


